mapper.update:
INSERT INTO NMCP_PUSH_SND_PROC_SCD_TRGT( PUSH_SEQ ,PUSH_SND_PROC_SNO ,PUSH_SND_SET_SNO ,USERID ,CELL_NO ,APP_OS_TP ,PROC_ST ,APP_OS_VER ,SND_PROC_DT ,SERVER_COLCT_YN ,APP_COLCT_YN ,PUSH_ICON_TP ,SND_TITLE ,SND_MSG ,LINK_DIV ,LINK_URL ,SND_CNT ,SND_TEST_YN ,TGT_SERVER ,SYS_REG_IP ,SYS_REG_DTIME ,SYS_REG_ID ,SYS_CHG_IP ,SYS_CHG_DTIME ,SYS_CHG_ID ,CURRENT_STAT ) SELECT ROWNUM AS RM, PUSH_SND_SET_SNO, PUSH_SND_SET_SNO, A.USERID AS USERID, A.MOBILE_NO AS CELL_NO, A.OS AS APP_OS_TP, '' AS PROC_ST, A.APP_OS_VER AS APP_OS_VER, SYSDATE AS SND_PROC_DT, 'N' AS SERVER_COLCT_YN, 'N' AS APP_COLCT_YN, '500' AS PUSH_ICON_TP, #{pushTitle} AS SND_TITLE, #{pushMsg} AS SND_MSG, 'A' AS LINK_DIV, #{pushLink} AS LINK_URL, 0 AS SND_CNT, 'N' AS SND_TEST_YN, 'admin' AS TGT_SERVER, #{rip} AS SYS_REG_IP, SYSDATE AS SYS_REG_DTIME, #{amdId} AS SYS_REG_ID, #{rip} AS SYS_CHG_IP, SYSDATE AS SYS_CHG_DTIME, #{amdId} AS SYS_CHG_ID, 'M' AS CURRENT_STAT FROM ( SELECT #{pushSndDd} AS PUSH_SND_SET_SNO, TMMB.USERID, TMMB.MOBILE_NO, TUMAI.OS, TUMAI.UDID, CASE WHEN INSTR(APP_OS_VER, '.', 1, 2) > 0 THEN SUBSTR(APP_OS_VER, 1, INSTR(APP_OS_VER, '.', 1, 2) - 1) WHEN INSTR(APP_OS_VER, '.', 1, 1) = 0 THEN APP_OS_VER || '.0' ELSE APP_OS_VER END AS APP_OS_VER, TUMAI.VERSION FROM MCP_USER TMMB LEFT JOIN ( SELECT UUID, UDID, USER_ID, LAST_ACCESS_DT, SEND_YN, OS, VERSION, APP_OS_VER FROM ( SELECT UUID, UDID, USER_ID, LAST_ACCESS_DT, SEND_YN, OS, VERSION, APP_OS_VER, RANK() OVER (PARTITION BY USER_ID ORDER BY UP_DT DESC) AS RNK FROM NMCP_USR_APP_INFO WHERE UDID IS NOT NULL ) WHERE RNK = 1 ) TUMAI ON TMMB.USERID = TUMAI.USER_ID INNER JOIN MSP_JUO_SUB_INFO@DL_MSP MSP ON TMMB.CUSTOMER_ID = MSP.CUSTOMER_ID INNER JOIN MCP_USER_CNTR_MNG TMMBC ON TMMB.USERID = TMMBC.USERID
INNER JOIN MSP_REQUEST_DTL@DL_MSP T5 ON MSP.CONTRACT_NUM = T5.CONTRACT_NUM
WHERE 1=1 AND REVOCATION_DATE IS NULL AND TUMAI.UUID IS NOT NULL AND TUMAI.SEND_YN = 'Y' AND TMMB.USER_DIVISION = '01' AND TMMBC.REP_NO = 'R' AND TMMBC.SVC_CNTR_NO = MSP.SVC_CNTR_NO AND MSP.SUB_STATUS = 'A' AND TMMB.CLAUSE_PRI_AD_FLAG = 'Y'
AND T5.MOVE_COMPANY IN
#{item}
) A
